from flask import Flask, request, jsonify
from selenium import webdriver
from selenium.webdriver.chrome.service import Service as ChromeService
from webdriver_manager.chrome import ChromeDriverManager
from PIL import Image
import boto3
import os
import time

app = Flask(__name__)

s3_client = boto3.client('s3')
BUCKET_NAME = 'your-s3-bucket-name'

def take_screenshot(url):
    options = webdriver.ChromeOptions()
    options.add_argument('--headless')
    options.add_argument('--no-sandbox')
    options.add_argument('--disable-dev-shm-usage')
    driver = webdriver.Chrome(service=ChromeService(ChromeDriverManager().install()), options=options)
    driver.get(url)
    time.sleep(2)  # Allow time for the page to load
    screenshot = driver.get_screenshot_as_png()
    driver.quit()
    
    return screenshot

def save_to_s3(screenshot, filename):
    s3_client.put_object(Bucket=BUCKET_NAME, Key=filename, Body=screenshot, ContentType='image/png')

@app.route('/screenshot', methods=['POST'])
def screenshot_service():
    data = request.json
    url = data.get('url')
    if not url:
        return jsonify({'error': 'URL is required'}), 400

    screenshot = take_screenshot(url)
    filename = f"{int(time.time())}.png"
    save_to_s3(screenshot, filename)

    return jsonify({'message': 'Screenshot taken', 'url': f'https://{BUCKET_NAME}.s3.amazonaws.com/{filename}'})

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)